using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.UnitTests;/// <summary>/// Good case: Retrieve all files attached to an EHR record/// Expected: 200 OK with file list/// </summary>public class EhrServiceTests_GetEhrFiles_WithValidEhr_ShouldReturnFileList : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "EhrService"    };    [SkippableFact]    public async Task GetEhrFiles_WithValidEhr_ShouldReturnFileList()    {        await AuthenticateAsDoctorAsync(EhrClient);        // Step 1: Create an EHR record        var createRequest = new         {             patientId = TestSeedData.PatientUserId,             orgId = TestSeedData.HospitalAOrgId,             encounterId = Guid.NewGuid(),             data = new             {                 doctorId = TestSeedData.DoctorUserId,                 diagnosis = "File test",                 treatment = "Test treatment",                 notes = "Files list test"             }         };        var createResponse = await PostAsJsonWithRetryAsync(EhrClient, ApiEndpoints.Ehr.CreateRecord, createRequest);        var createJson = await ReadJsonResponseAsync(createResponse);                if (!createJson.TryGetProperty("ehrId", out var ehrIdElement))            return; // Skip if creation fails        var ehrId = Guid.Parse(ehrIdElement.GetString()!);        // Step 2: Get files list        var filesResponse = await GetWithRetryAsync(EhrClient, ApiEndpoints.Ehr.Files(ehrId));        Assert.Equal(HttpStatusCode.OK, filesResponse.StatusCode);                var filesJson = await ReadJsonResponseAsync(filesResponse);        Assert.True(filesJson.ValueKind == JsonValueKind.Array, "Should return array of files");    }}